  ('bookkeeper-moex-00301', 'bookkeeper', 'bookkeeper-moex-112-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '我國A海運公司112年相關交易情形如下：①銷售國際運輸用之船舶  ②進口國際運輸用之船舶  ③進', '["銷售供漁船使用之機器設備之用油。以上何種銷售情形免徵 營業稅？", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:20+00:00", "source_pdf_sha1": "9066e7c04cf0", "answer_pdf_sha1": "40c7949d0c8e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112190", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "112", "exam_name": "112年專技人員高等考試建築師、25類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
